function ProfileCard({ name, job, description, avatarUrl }) {
  return (
    &lt;div className="profile-card"&gt;
      &lt;img src={avatarUrl} alt={`Photo de ${name}`} /&gt;
      &lt;h2&gt;{name}&lt;/h2&gt;
      &lt;p className="job"&gt;{job}&lt;/p&gt;
      &lt;p&gt;{description}&lt;/p&gt;
    &lt;/div&gt;
  );
}

export default ProfileCard;

import ProfileCard from './ProfileCard';

function App() {
  return (
    &lt;div&gt;
      &lt;ProfileCard 
        name="Alice" 
        job="Développeuse React" 
        description="Passionnée par les interfaces modernes" 
        avatarUrl="/alice.jpg" 
      /&gt;
      &lt;ProfileCard 
        name="Bob" 
        job="UI Designer" 
        description="Créatif et minutieux" 
        avatarUrl="/bob.jpg" 
      /&gt;
    &lt;/div&gt;
  );
}

function ProfileCard({ name, job, description, avatarUrl, isOnline = false }) {
  return (
    &lt;div className="profile-card"&gt;
      &lt;img src={avatarUrl} alt={name} /&gt;
      &lt;h2&gt;
        {name} 
        {isOnline && &lt;span className="online-badge"&gt;🟢 En ligne&lt;/span&gt;}
      &lt;/h2&gt;
      &lt;p className="job"&gt;{job}&lt;/p&gt;
      &lt;p&gt;{description}&lt;/p&gt;
    &lt;/div&gt;
  );
}

function ProductList({ products }) {
  const total = products.reduce((sum, product) => sum + product.price, 0);

  return (
    &lt;div&gt;
      &lt;h2&gt;Liste des produits&lt;/h2&gt;
      &lt;ul&gt;
        {products.map(product => (
          &lt;li key={product.id}&gt;
            {product.name} - {product.price} €
          &lt;/li&gt;
        ))}
      &lt;/ul&gt;
      &lt;p&gt;&lt;strong&gt;Total : {total} €&lt;/strong&gt;&lt;/p&gt;
    &lt;/div&gt;
  );
}

function App() {
  const produits = [
    { id: 1, name: 'Clavier', price: 45 },
    { id: 2, name: 'Souris', price: 25 },
    { id: 3, name: 'Écran', price: 180 }
  ];
  return &lt;ProductList products={produits} /&gt;;
}

function ProductList({ products }) {
  const total = products.reduce((sum, p) => {
    const price = p.onSale ? p.price * 0.9 : p.price;
    return sum + price;
  }, 0);

  return (
    &lt;div&gt;
      &lt;ul&gt;
        {products.map(p => {
          const finalPrice = p.onSale ? p.price * 0.9 : p.price;
          return (
            &lt;li key={p.id}&gt;
              {p.name} - 
              {p.onSale ? (
                &lt;&gt;
                  &lt;span style={{ textDecoration: 'line-through' }}&gt;{p.price}€&lt;/span&gt; 
                  {finalPrice}€
                &lt;/&gt;
              ) : (
                `${finalPrice}€`
              )}
            &lt;/li&gt;
          );
        })}
      &lt;/ul&gt;
      &lt;p&gt;Total : {total.toFixed(2)}€&lt;/p&gt;
    &lt;/div&gt;
  );
}
